// Renders the Trello-style board from board.json (generated by `npm run build`).

const boardEl = document.getElementById("board");
const updatedEl = document.getElementById("updated");
const searchEl = document.getElementById("search");

function el(tag, props = {}, children = []) {
  const node = document.createElement(tag);
  Object.assign(node, props);
  for (const [k, v] of Object.entries(props.dataset || {})) node.dataset[k] = v;
  for (const child of [].concat(children)) {
    if (child != null) node.append(child);
  }
  return node;
}

function renderCard(issue) {
  const summary = el("p", { className: "card-summary", textContent: issue.summary });

  const key = el("span", { className: "card-key", textContent: issue.key });
  const status = el("span", {
    className: "status",
    textContent: issue.status,
    dataset: { cat: issue.statusCategory },
  });

  const footerChildren = [key, status];
  if (issue.assigneeAvatar) {
    footerChildren.push(
      el("img", {
        className: "assignee",
        src: issue.assigneeAvatar,
        alt: issue.assignee || "",
        title: issue.assignee || "",
        loading: "lazy",
      })
    );
  }
  const footer = el("div", { className: "card-footer" }, footerChildren);

  const card = el(
    "a",
    {
      className: "card",
      href: issue.url,
      target: "_blank",
      rel: "noopener",
      dataset: { cat: issue.statusCategory },
    },
    [summary, footer]
  );
  card._search = `${issue.key} ${issue.summary} ${issue.status} ${issue.assignee || ""}`.toLowerCase();
  return card;
}

function renderColumn(column) {
  const header = el("div", { className: "column-header" }, [
    el("span", { textContent: column.label }),
    el("span", { className: "count", textContent: String(column.issues.length) }),
  ]);
  const cards = el("div", { className: "cards" }, column.issues.map(renderCard));
  return el("div", { className: "column" }, [header, cards]);
}

function applyFilter(term) {
  const q = term.trim().toLowerCase();
  for (const col of boardEl.querySelectorAll(".column")) {
    let visible = 0;
    for (const card of col.querySelectorAll(".card")) {
      const match = !q || card._search.includes(q);
      card.classList.toggle("hidden", !match);
      if (match) visible++;
    }
    col.classList.toggle("hidden", q && visible === 0);
  }
}

async function init() {
  try {
    const res = await fetch("board.json", { cache: "no-store" });
    if (!res.ok) throw new Error(`board.json not found (${res.status})`);
    const board = await res.json();

    boardEl.replaceChildren(...board.columns.map(renderColumn));

    if (board.generatedAt) {
      const d = new Date(board.generatedAt);
      updatedEl.textContent = `Updated ${d.toLocaleString()} · ${board.totalIssues} issues`;
    }

    searchEl.addEventListener("input", (e) => applyFilter(e.target.value));
  } catch (err) {
    boardEl.replaceChildren(
      el("div", { className: "error" }, [
        el("strong", { textContent: "Could not load board data. " }),
        el("span", {
          textContent:
            "Run `npm run build` to generate docs/board.json, then reload. " + err.message,
        }),
      ])
    );
  }
}

init();
